// ── SHARE ──────────────────────────────────
function shareText(text){
  if(navigator.share){
    navigator.share({text:text}).catch(()=>{});
  } else {
    navigator.clipboard.writeText(text).then(()=>{
      const msg=isEn()?'Copied to clipboard!':'¡Copiado al portapapeles!';
      showToast(msg);
    });
  }
}

function showToast(msg){
  let t=document.getElementById('share-toast');
  if(!t){t=document.createElement('div');t.id='share-toast';
    t.style.cssText='position:fixed;bottom:80px;left:50%;transform:translateX(-50%);background:var(--brown);color:#fff;padding:8px 18px;border-radius:99px;font-size:13px;z-index:9999;opacity:0;transition:opacity .3s;';
    document.body.appendChild(t);}
  t.textContent=msg;t.style.opacity='1';
  setTimeout(()=>{t.style.opacity='0';},2000);
}

function shareTasks(){
  const di=dayIdx();
  const tasks=tasksForDay(di);
  const dateStr=DIAS[activeDate.getDay()]+', '+activeDate.getDate()+' de '+MES[activeDate.getMonth()];
  const undone=tasks.filter(t=>t.doneOnDay===undefined);
  const done=tasks.filter(t=>t.doneOnDay!==undefined);
  let txt=isEn()?'To-do — '+dateStr+'\n':'Pendientes — '+dateStr+'\n';
  txt+='\n';
  undone.forEach(t=>{txt+='• '+t.text+'\n';});
  if(done.length){
    txt+='\n'+(isEn()?'Done:':'Completados:')+'\n';
    done.forEach(t=>{txt+='✓ '+t.text+'\n';});
  }
  if(!undone.length&&!done.length)txt+=(isEn()?'No tasks yet':'Sin pendientes aún');
  shareText(txt.trim());
}

function shareShopping(){
  const cats=setupCfg.shopCats||DEFAULT_SHOP;
  let txt=isEn()?'Shopping List\n':'Lista de compras\n';
  txt+='\n';
  cats.forEach((cat,idx)=>{
    const key='cat'+idx;
    const items=(shoppingItems[key]||[]);
    if(items.length){
      const emoji=SHOP_EMOJI[cat]||'';
      txt+=emoji+' '+cat+':\n';
      items.forEach(i=>{txt+=(i.done?'✓ ~'+i.text+'~':'• '+i.text)+'\n';});
      txt+='\n';
    }
  });
  if(txt.trim()===(isEn()?'Shopping List':'Lista de compras'))
    txt+=(isEn()?'List is empty':'Lista vacía');
  shareText(txt.trim());
}

function shareGastos(){
  const di=dayIdx();
  const dateStr=DIAS[activeDate.getDay()]+', '+activeDate.getDate();
  let txt=(isEn()?'Expenses — ':'Gastos — ')+dateStr+'\n\n';
  const items=gastosForDay(di);
  if(items.length){
    items.forEach(g=>{txt+='• '+g.desc+' ('+g.cat+') — $'+g.monto.toLocaleString()+'\n';});
    const total=items.reduce((s,g)=>s+g.monto,0);
    txt+='\n'+(isEn()?'Total: ':'Total: ')+'$'+total.toLocaleString();
  } else {
    txt+=(isEn()?'No expenses today':'Sin gastos hoy');
  }
  shareText(txt.trim());
}

function shareFocus(){
  const di=dayIdx();
  const f=focusForDay(di);
  const dateStr=DIAS[activeDate.getDay()]+', '+activeDate.getDate()+' de '+MES[activeDate.getMonth()];
  let txt=(isEn()?'Focus — ':'Enfoque — ')+dateStr+'\n\n';
  const lines=[1,2,3].filter(n=>f[n]);
  if(lines.length){
    lines.forEach(n=>{const done=!!(weekData.focusDone&&weekData.focusDone[String(di)+'_'+String(n)]!==undefined);txt+=(done?'✓ ':'• ')+f[n]+'\n';});
  } else {
    txt+=(isEn()?'No focus set':'Sin enfoques aún');
  }
  shareText(txt.trim());
}

// ── MONTHLY BUDGET ──────────────────────────
let budgetYear=new Date().getFullYear();
let budgetMonth=new Date().getMonth();
let annualData={income:[],expenses:[]}; // annual income/expenses
let budgetData={income:[],groups:[],debts:[]};
let cardPeriodSums={};
let _lastDashboardTotals={};

async function loadBudgetDebts(){
  if(!db||!currentUser)return;
  try{
    const snap=await userCol().doc('budget_config').get();
    if(snap.exists){budgetData.debts=snap.data().debts||[];}
    buildPagoSelect();
  }catch(e){}
}

const MES_ES_B=['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const MES_EN_B=['January','February','March','April','May','June','July','August','September','October','November','December'];

function openBudget(){
  budgetYear=new Date().getFullYear();
  budgetMonth=new Date().getMonth();
  // Colapsar todos los grupos al abrir
  budgetCollapsedGroups.clear();
  (budgetData.groups||[]).forEach((_,i)=>budgetCollapsedGroups.add(i));
  document.getElementById('budget-modal').style.display='block';
  document.body.style.overflow='hidden';
  loadBudgetData();
}

function showBudgetExportMenu(){
  const menu=document.getElementById('budget-export-menu');
  menu.style.display=menu.style.display==='none'||!menu.style.display?'block':'none';
  setTimeout(()=>{
    if(menu.style.display==='block'){
      document.addEventListener('click',function close(e){
        if(!e.target.closest('#budget-export-menu')&&!e.target.closest('[onclick="showBudgetExportMenu()"]')){
          menu.style.display='none';
          document.removeEventListener('click',close);
        }
      });
    }
  },0);
}

async function budgetExportPDF(){
  document.getElementById('budget-export-menu').style.display='none';
  const {jsPDF}=window.jspdf;
  const pdf=new jsPDF({orientation:'portrait',unit:'mm',format:'a4'});
  const es=!isEn();
  // Strip emojis from any string
  const clean=s=>(s||'').replace(/[\u{1F000}-\u{1FFFF}\u{1F300}-\u{1F9FF}\u{2600}-\u{27BF}\u{2300}-\u{23FF}\u{FE00}-\u{FEFF}]/gu,'').trim();
  const monthLbl=document.getElementById('budget-month-lbl').textContent;
  const fmt=n=>'$'+(Math.round(n)||0).toLocaleString();
  const pw=190; // page width usable
  let y=10;
  const COL={presupR:130,actualR:158,rubroR:200,presupW:28,actualW:28,rubroW:35};
  const fitNum=(text,colW)=>{
    const orig=pdf.getFontSize();
    let sz=orig;
    while(pdf.getTextWidth(text)>colW&&sz>7){sz-=0.5;pdf.setFontSize(sz);}
    return orig;
  };

  // Colors
  const mauveC=[171,130,130];
  const tealC=[97,137,133];
  const grayC=[150,150,150];
  const darkC=[30,30,30];
  const lightC=[245,243,240];

  // LOGO + HEADER
  try{
    pdf.addImage('data:image/png;base64,','PNG',10,y,18,18);
  }catch(e){}
  pdf.setFontSize(16);pdf.setFont('helvetica','bold');pdf.setTextColor(...darkC);
  pdf.text('Weekly Planner',32,y+7);
  pdf.setFontSize(9);pdf.setFont('helvetica','normal');pdf.setTextColor(...grayC);
  pdf.text((es?'Presupuesto mensual':'Monthly Budget')+' — '+monthLbl,32,y+13);
  y+=24;
  pdf.setDrawColor(220,215,210);pdf.setLineWidth(0.3);pdf.line(10,y,200,y);y+=6;

  // INGRESOS
  const totalInc=budgetData.income.reduce((s,i)=>s+i.amt,0);
  pdf.setFontSize(8);pdf.setFont('helvetica','bold');pdf.setTextColor(...grayC);
  pdf.text(es?'INGRESOS':'INCOME',10,y);y+=9;
  pdf.setFillColor(...lightC);pdf.roundedRect(10,y,pw,10,2,2,'F');
  pdf.setFontSize(10);pdf.setFont('helvetica','bold');pdf.setTextColor(...darkC);
  pdf.text(es?'Total ingresos':'Total income',13,y+6);
  pdf.text(fmt(totalInc),200,y+6,{align:'right'});
  y+=17;
  budgetData.income.forEach(inc=>{
    pdf.setFontSize(9);pdf.setFont('helvetica','normal');pdf.setTextColor(60,60,60);
    pdf.text(inc.desc,15,y);
    pdf.text(fmt(inc.amt),200,y,{align:'right'});
    y+=7;
  });
  y+=5;pdf.setDrawColor(220,215,210);pdf.line(10,y,200,y);y+=7;

  // STATS GRID
  const totalPresup=budgetData.groups.reduce((s,g)=>s+g.subs.reduce((ss,sub)=>ss+sub.presup,0),0);
  const totalManual=budgetData.groups.reduce((s,g)=>s+g.subs.reduce((ss,sub)=>ss+sub.actual,0),0);
  const dashSnap=await loadMonthGastos();
  const totalDash=Object.values(dashSnap).reduce((s,v)=>s+v,0);
  const totalAbonosPDF=(budgetData.debts||[]).reduce((s,d)=>s+(d.abono||0),0);
  const disponible=totalInc-totalDash-totalAbonosPDF;

  const stats=[
    [es?'Total ingresos':'Total income',fmt(totalInc)],
    [es?'Presupuestado':'Budgeted',fmt(totalPresup)],
    [es?'Sin presupuestar':'Unbudgeted',fmt(totalInc-totalPresup)],
    [es?'Actual manual':'Manual actual',fmt(totalManual)],
    ['Dashboard',fmt(totalDash)],
    [es?'Disponible':'Available',fmt(disponible)],
  ];
  const colW=pw/3;
  stats.forEach((s,i)=>{
    const col=i%3;const row=Math.floor(i/3);
    const sx=10+col*colW;const sy=y+row*14;
    pdf.setFillColor(...lightC);pdf.roundedRect(sx,sy,colW-2,12,1.5,1.5,'F');
    pdf.setFontSize(11);pdf.setFont('helvetica','bold');pdf.setTextColor(...darkC);
    pdf.text(s[1],sx+colW/2-1,sy+6,{align:'center'});
    pdf.setFontSize(7);pdf.setFont('helvetica','normal');pdf.setTextColor(...grayC);
    pdf.text(s[0],sx+colW/2-1,sy+10,{align:'center'});
  });
  y+=32;pdf.setDrawColor(220,215,210);pdf.line(10,y,200,y);y+=6;

  // GRUPOS
  pdf.setFontSize(8);pdf.setFont('helvetica','bold');pdf.setTextColor(...grayC);
  pdf.text(es?'GASTOS PLANEADOS':'PLANNED EXPENSES',10,y);y+=9;

  budgetData.groups.forEach(group=>{
    if(y>260){pdf.addPage();y=10;}
    const gPresup=group.subs.reduce((s,sub)=>s+sub.presup,0);
    const gActual=group.subs.reduce((s,sub)=>s+sub.actual,0);
    // Group header
    pdf.setFillColor(240,235,230);pdf.roundedRect(10,y,pw,7,1,1,'F');
    pdf.setFontSize(8);pdf.setFont('helvetica','bold');pdf.setTextColor(26,26,26);
    const _rightTxt=fmt(gActual)+' / '+fmt(gPresup);
    const _maxNameW=pw-pdf.getTextWidth(_rightTxt)-8;
    let gName=clean(group.name).toUpperCase();
    while(pdf.getTextWidth(gName+'...')>_maxNameW&&gName.length>1)gName=gName.slice(0,-1);
    pdf.text(gName+(gName!==clean(group.name).toUpperCase()?'...':''),13,y+4.5);
    pdf.text(_rightTxt,196,y+4.5,{align:'right'});
    y+=13;
    // Col headers
    pdf.setFontSize(7);pdf.setFont('helvetica','normal');pdf.setTextColor(...grayC);
    pdf.text(es?'Subcategoría':'Subcategory',13,y);
    pdf.text(es?'Presup.':'Budget',130,y,{align:'right'});
    pdf.text(es?'Actual':'Actual',158,y,{align:'right'});
    pdf.text(es?'Rubro':'Category',200,y,{align:'right'});
    y+=5;pdf.setDrawColor(230,225,220);pdf.line(10,y,200,y);y+=4;
    // Subs
    group.subs.forEach(sub=>{
      if(y>265){pdf.addPage();y=10;}
      const ok=sub.presup>0&&sub.actual<=sub.presup;
      const over=sub.presup>0&&sub.actual>sub.presup;
      pdf.setFontSize(8);pdf.setFont('helvetica','normal');pdf.setTextColor(...darkC);
      if(ok){pdf.setDrawColor(...tealC);pdf.line(13,y+0.5,13+pdf.getTextWidth(clean(sub.name)),y+0.5);}
      if(over){pdf.setDrawColor(192,57,43);pdf.line(13,y+0.5,13+pdf.getTextWidth(clean(sub.name)),y+0.5);}
      pdf.text(clean(sub.name),13,y);
      const _pTxt=fmt(sub.presup);const _pOrig=fitNum(_pTxt,COL.presupW);pdf.setTextColor(...darkC);pdf.text(_pTxt,COL.presupR,y,{align:'right'});pdf.setFontSize(_pOrig);
      const _aTxt=fmt(sub.actual);const _aOrig=fitNum(_aTxt,COL.actualW);pdf.setTextColor(...darkC);pdf.text(_aTxt,COL.actualR,y,{align:'right'});pdf.setFontSize(_aOrig);
      const _rTxt=clean(sub.rubro||'—');pdf.setFontSize(7);pdf.setTextColor(...grayC);const _rW=pdf.getTextWidth(_rTxt);pdf.text(_rTxt,COL.rubroR-_rW,y);pdf.setFontSize(8);
      y+=7;
    });
    y+=6;
  });

  // RESUMEN POR RUBRO
  if(y>220){pdf.addPage();y=10;}
  y+=2;pdf.setDrawColor(220,215,210);pdf.line(10,y,200,y);y+=6;
  pdf.setFontSize(8);pdf.setFont('helvetica','bold');pdf.setTextColor(...grayC);
  pdf.text(es?'RESUMEN POR RUBRO DE GASTOS':'EXPENSE SUMMARY BY CATEGORY',10,y);y+=9;

  // Table headers
  pdf.setFillColor(...lightC);pdf.rect(10,y,pw,6,'F');
  pdf.setFontSize(7);pdf.setFont('helvetica','bold');pdf.setTextColor(...grayC);
  pdf.text(es?'Rubro':'Category',13,y+4);
  pdf.text(es?'Presupuesto':'Budget',85,y+4,{align:'right'});
  pdf.text(es?'Manual':'Manual',115,y+4,{align:'right'});
  pdf.text('Dashboard',148,y+4,{align:'right'});
  pdf.text(es?'Diferencia':'Difference',174,y+4,{align:'right'});
  pdf.text(es?'Sin clasificar':'Unclassified',200,y+4,{align:'right'});
  y+=8;

  const rubroMap={};
  budgetData.groups.forEach(g=>{
    g.subs.forEach(sub=>{
      if(!sub.rubro||sub.rubro==='—')return;
      if(!rubroMap[sub.rubro])rubroMap[sub.rubro]={presup:0,manual:0};
      rubroMap[sub.rubro].presup+=sub.presup;
      rubroMap[sub.rubro].manual+=sub.actual;
    });
  });
  Object.entries(dashSnap).forEach(([cat,total])=>{if(total>0&&!rubroMap[cat])rubroMap[cat]={presup:0,manual:0};});

  let tP=0,tM=0,tD=0,tS=0;
  Object.entries(rubroMap).forEach(([rubro,data])=>{
    if(y>270){pdf.addPage();y=10;}
    const dash=dashSnap[rubro]||0;
    const diff=data.presup-dash;
    const sinc=Math.max(0,dash-data.manual);
    tP+=data.presup;tM+=data.manual;tD+=dash;tS+=sinc;
    pdf.setFontSize(8);pdf.setFont('helvetica','normal');pdf.setTextColor(...darkC);
    let _rLbl=clean(rubro);while(pdf.getTextWidth(_rLbl)>68&&_rLbl.length>1)_rLbl=_rLbl.slice(0,-1);
    if(_rLbl!==clean(rubro))_rLbl+='...';
    pdf.text(_rLbl,13,y);
    pdf.text(fmt(data.presup),85-pdf.getTextWidth(fmt(data.presup)),y);
    pdf.text(fmt(data.manual),115-pdf.getTextWidth(fmt(data.manual)),y);
    pdf.text(fmt(dash),148-pdf.getTextWidth(fmt(dash)),y);
    diff>=0?pdf.setTextColor(...tealC):pdf.setTextColor(192,57,43);
    const _dTxt=(diff>=0?'+':'')+fmt(diff);pdf.text(_dTxt,174-pdf.getTextWidth(_dTxt),y);
    sinc>0?pdf.setTextColor(230,100,0):pdf.setTextColor(...grayC);
    pdf.text(fmt(sinc),200-pdf.getTextWidth(fmt(sinc)),y);
    pdf.setDrawColor(230,225,220);pdf.line(10,y+1.5,200,y+1.5);
    y+=6;
  });
  // Total row
  pdf.setFillColor(...lightC);pdf.rect(10,y,pw,7,'F');
  pdf.setFontSize(8);pdf.setFont('helvetica','bold');pdf.setTextColor(...darkC);
  pdf.text('Total',13,y+5);
  pdf.text(fmt(tP),85,y+5,{align:'right'});
  pdf.text(fmt(tM),115,y+5,{align:'right'});
  pdf.text(fmt(tD),148,y+5,{align:'right'});
  tP-tD>=0?pdf.setTextColor(...tealC):pdf.setTextColor(192,57,43);
  pdf.text((tP-tD>=0?'+':'')+fmt(tP-tD),174,y+5,{align:'right'});
  tS>0?pdf.setTextColor(230,100,0):pdf.setTextColor(...grayC);
  pdf.text(fmt(tS),200,y+5,{align:'right'});

  pdf.save('presupuesto_'+monthLbl.replace(' ','_')+'.pdf');
}


function budgetExportExcel(){
  document.getElementById('budget-export-menu').style.display='none';
  const monthLbl=document.getElementById('budget-month-lbl').textContent;
  const es=!isEn();
  const wb=XLSX.utils.book_new();
  const fmt=n=>(Math.round(n)||0);
  const addSheet=(wb,data,name,cols)=>{const ws=XLSX.utils.aoa_to_sheet(data);if(cols)ws['!cols']=cols;XLSX.utils.book_append_sheet(wb,ws,name);};

  // Totals
  const totalInc=budgetData.income.reduce((s,i)=>s+i.amt,0);
  const totalPresup=budgetData.groups.reduce((s,g)=>s+g.subs.reduce((ss,sub)=>ss+sub.presup,0),0);
  const totalManual=budgetData.groups.reduce((s,g)=>s+g.subs.reduce((ss,sub)=>ss+sub.actual,0),0);
  const totalAbonos=(budgetData.debts||[]).reduce((s,d)=>s+(d.abono||0),0);
  const totalDash=Object.values(_lastDashboardTotals).reduce((s,v)=>s+v,0);
  const disponible=totalInc-totalDash-totalAbonos;
  const sinPresup=totalInc-totalPresup;

  // 1. Resumen del mes
  const sumData=[
    [es?'RESUMEN DEL MES':'MONTH SUMMARY',''],
    [''],
    [es?'Concepto':'Concept',es?'Monto':'Amount'],
    [es?'Total ingresos':'Total income',fmt(totalInc)],
    [es?'Gastos del dashboard':'Dashboard expenses',fmt(totalDash)],
    [es?'Disponible':'Available',fmt(disponible)],
    [es?'Presupuestado':'Budgeted',fmt(totalPresup)],
    [es?'Real — capturado':'Real — captured',fmt(totalManual)],
    [es?'Sin presupuestar':'Unbudgeted',fmt(sinPresup)],
  ];
  if(totalAbonos>0)sumData.push([es?'Abonos deudas':'Debt payments',fmt(totalAbonos)]);
  addSheet(wb,sumData,es?'Resumen':'Summary',[{wch:28},{wch:15}]);

  // 2. Ingresos
  const incData=[[es?'Descripción':'Description',es?'Monto':'Amount']];
  budgetData.income.forEach(i=>incData.push([i.desc,fmt(i.amt)]));
  incData.push(['']);incData.push([es?'TOTAL':'TOTAL',fmt(totalInc)]);
  addSheet(wb,incData,es?'Ingresos':'Income',[{wch:28},{wch:15}]);

  // 3. Gastos planeados
  const budData=[[es?'Grupo':'Group',es?'Subcategoría':'Subcategory',es?'Presupuesto':'Budget',es?'Real':'Actual',es?'Rubro':'Category']];
  budgetData.groups.forEach(g=>{
    g.subs.forEach(sub=>budData.push([g.name,sub.name,fmt(sub.presup),fmt(sub.actual),sub.rubro||'—']));
    const gP=g.subs.reduce((s,sub)=>s+sub.presup,0);
    const gA=g.subs.reduce((s,sub)=>s+sub.actual,0);
    budData.push(['',es?'Subtotal':'Subtotal',fmt(gP),fmt(gA),'']);
    budData.push(['']);
  });
  addSheet(wb,budData,es?'Gastos planeados':'Planned expenses',[{wch:20},{wch:25},{wch:15},{wch:15},{wch:20}]);

  // 4. Resumen por rubro
  const rubroMap={};
  budgetData.groups.forEach(g=>g.subs.forEach(sub=>{
    if(!sub.rubro||sub.rubro==='—')return;
    if(!rubroMap[sub.rubro])rubroMap[sub.rubro]={presup:0,manual:0};
    rubroMap[sub.rubro].presup+=sub.presup;rubroMap[sub.rubro].manual+=sub.actual;
  }));
  const resData=[[es?'Rubro':'Category',es?'Presupuestado':'Budgeted',es?'Real':'Actual',es?'Dashboard':'Dashboard',es?'Diferencia':'Difference']];
  Object.entries(rubroMap).forEach(([rubro,d])=>{
    const dash=_lastDashboardTotals[rubro]||0;
    resData.push([rubro,fmt(d.presup),fmt(d.manual),fmt(dash),fmt(d.presup-d.manual)]);
  });
  addSheet(wb,resData,es?'Por rubro':'By category',[{wch:25},{wch:15},{wch:15},{wch:15},{wch:15}]);

  // 5. Crédito, Préstamos y Deudas
  if((budgetData.debts||[]).length>0){
    const debtData=[[es?'Nombre':'Name',es?'Tipo':'Type',es?'Saldo':'Balance',es?'Abono':'Payment',es?'Tasa %':'Rate %',es?'Fecha pago':'Pay date']];
    budgetData.debts.forEach(d=>debtData.push([d.nombre,d.tipo||'—',fmt(d.saldo||0),fmt(d.abono||0),d.tasa||0,d.fechaPago||'—']));
    debtData.push(['']);debtData.push([es?'Total abonos':'Total payments','','',fmt(totalAbonos),'','']);
    addSheet(wb,debtData,es?'Deudas':'Debts',[{wch:25},{wch:12},{wch:15},{wch:15},{wch:10},{wch:15}]);
  }

  // 6. Ingresos y gastos anuales
  const hasAnnual=(annualData.income&&annualData.income.length>0)||(annualData.expenses&&annualData.expenses.length>0);
  if(hasAnnual){
    const annData=[[es?'INGRESOS ANUALES':'ANNUAL INCOME','']];
    annData.push([es?'Descripción':'Description',es?'Monto':'Amount']);
    (annualData.income||[]).forEach(i=>annData.push([i.desc,fmt(i.amt)]));
    const annInc=(annualData.income||[]).reduce((s,i)=>s+i.amt,0);
    annData.push(['',fmt(annInc)]);
    annData.push(['']);
    annData.push([es?'GASTOS ANUALES':'ANNUAL EXPENSES','',es?'Mes':'Month']);
    annData.push([es?'Descripción':'Description',es?'Monto':'Amount',es?'Mes':'Month']);
    (annualData.expenses||[]).forEach(e=>annData.push([e.desc,fmt(e.amt),e.month||'']));
    const annExp=(annualData.expenses||[]).reduce((s,e)=>s+e.amt,0);
    annData.push(['',fmt(annExp),'']);
    annData.push(['']);
    annData.push([es?'Neto mensual promedio':'Monthly net avg',fmt((annInc-annExp)/12),'']);
    addSheet(wb,annData,es?'Anual':'Annual',[{wch:28},{wch:15},{wch:15}]);
  }

  const fileName=(isEn()?'budget_':'presupuesto_')+monthLbl.replace(' ','_')+'.xlsx';
  XLSX.writeFile(wb,fileName);
}

async function restoreBudgetFromBackup(){
  if(!db||!currentUser)return;
  const msg=isEn()
    ?'If you continue, your budget will revert to the last saved backup. Any changes made after that backup will be lost. Are you sure?'
    :'Si continúas, tu presupuesto regresará al último respaldo guardado. Cualquier cambio nuevo que hayas hecho después de ese respaldo se perderá. ¿Estás seguro?';
  if(!confirm(msg))return;
  try{
    const snap=await userCol().doc('budget_config_backup').get();
    if(!snap.exists){alert(isEn()?'No backup found':'No se encontró respaldo');return;}
    const data=snap.data();
    delete data._backup_ts;
    await userCol().doc('budget_config').set(data);
    budgetData=data;
    if(!budgetData.debts)budgetData.debts=[];
    const dash=await loadMonthGastos();
    renderBudget(dash);
    showToast(isEn()?'Budget restored from backup':'Presupuesto restaurado del respaldo');
  }catch(e){
    console.error('Restore failed:',e);
    alert(isEn()?'Restore failed: '+e.message:'Error al restaurar: '+e.message);
  }
}

async function closeBudget(){
  await saveBudgetData(); // safe - won't save if data is empty
  document.getElementById('budget-modal').style.display='none';
  document.body.style.overflow='';
}

function budgetPrevMonth(){budgetMonth--;if(budgetMonth<0){budgetMonth=11;budgetYear--;}loadBudgetData();}
function budgetNextMonth(){
  const now=new Date();
  if(budgetYear===now.getFullYear()&&budgetMonth>=now.getMonth())return;
  budgetMonth++;if(budgetMonth>11){budgetMonth=0;budgetYear++;}
  loadBudgetData();
}

async function loadBudgetData(){
  const meses=isEn()?MES_EN_B:MES_ES_B;
  document.getElementById('budget-month-lbl').textContent=meses[budgetMonth]+' '+budgetYear;
  const modalTitle=document.getElementById('budget-modal-title');
  if(modalTitle)modalTitle.textContent=isEn()?'Monthly Budget':'Presupuesto mensual';
  const pdfBtn=document.getElementById('budget-pdf-btn');
  const xlsBtn=document.getElementById('budget-excel-btn');
  if(pdfBtn)pdfBtn.innerHTML='<i data-lucide="file-text" style="width:15px;height:15px;flex-shrink:0;"></i>'+(isEn()?'Download PDF':'Descargar PDF');
  if(xlsBtn)xlsBtn.innerHTML='<i data-lucide="file-spreadsheet" style="width:15px;height:15px;flex-shrink:0;"></i>'+(isEn()?'Download Excel':'Descargar Excel');
  if(typeof lucide!=='undefined')lucide.createIcons();
  const loadingEl=document.getElementById('budget-loading');
  if(loadingEl)loadingEl.textContent=isEn()?'Loading...':'Cargando...';
  const nextBtn=document.getElementById('budget-next-btn');
  const now=new Date();
  if(nextBtn)nextBtn.style.opacity=(budgetYear===now.getFullYear()&&budgetMonth>=now.getMonth())?'0.3':'1';

  // Load budget config from Firebase
  if(db&&currentUser){
    try{
      const snap=await userCol().doc('budget_config').get();
      if(snap.exists){
        budgetData=snap.data();
        if(!budgetData.income)budgetData.income=[];
        if(!budgetData.groups)budgetData.groups=getDefaultGroups();
        if(!budgetData.debts)budgetData.debts=[];
      } else {
        budgetData={income:[],groups:getDefaultGroups(),debts:[]};
      }
      await ensureIds();
      // Load actuals for this specific month (separate doc)
      const monthKey='budget_actual_'+budgetYear+'_'+String(budgetMonth+1).padStart(2,'0');
      const actualSnap=await userCol().doc(monthKey).get();
      // Always load prev month so saldoInicialMes stays fresh even with retroactive edits
      const prevMonthIdx=budgetMonth===0?11:budgetMonth-1;
      const prevYearIdx=budgetMonth===0?budgetYear-1:budgetYear;
      const prevKey='budget_actual_'+prevYearIdx+'_'+String(prevMonthIdx+1).padStart(2,'0');
      let prevActuals=null;
      try{const ps=await userCol().doc(prevKey).get();if(ps.exists)prevActuals=ps.data();}catch(e){}
      if(actualSnap.exists){
        const monthActuals=actualSnap.data();
        // Apply monthly actuals to groups
        budgetData.groups.forEach((g,gi)=>{
          g.subs.forEach((sub,si)=>{
            const newKey=g.id+'_'+sub.id;
            const oldKey=gi+'_'+si;
            if(monthActuals[newKey]!==undefined)sub.actual=monthActuals[newKey];
            else if(monthActuals[oldKey]!==undefined)sub.actual=monthActuals[oldKey];
            else sub.actual=0;
          });
        });
        // Derive saldoInicialMes from previous month so retroactive abono changes propagate
        let saldoChanged=false;
        (budgetData.debts||[]).forEach((debt,di)=>{
          const did=debt.id;const op='debt_'+di;
          const abono=monthActuals[did+'_abono']!==undefined?monthActuals[did+'_abono']:monthActuals[op+'_abono']!==undefined?monthActuals[op+'_abono']:0;
          debt.abono=abono;
          const prevSaldo=prevActuals?(prevActuals[did+'_saldo']!==undefined?prevActuals[did+'_saldo']:prevActuals[op+'_saldo']):undefined;
          const curSaldoInicial=monthActuals[did+'_saldoInicial']!==undefined?monthActuals[did+'_saldoInicial']:monthActuals[op+'_saldoInicial'];
          const curSaldo=monthActuals[did+'_saldo']!==undefined?monthActuals[did+'_saldo']:monthActuals[op+'_saldo'];
          const saldoInicial=prevSaldo!==undefined?prevSaldo:curSaldoInicial!==undefined?curSaldoInicial:(curSaldo||0)+(abono||0);
          debt.saldoInicialMes=saldoInicial;
          const newSaldo=Math.max(0,saldoInicial-abono);
          if(newSaldo!==(curSaldo!==undefined?curSaldo:debt.saldo||0))saldoChanged=true;
          debt.saldo=newSaldo;
        });
        // Income lives in budget_config — already loaded above, don't override
        // Auto-save updated saldos so the next month in the chain stays consistent
        if(saldoChanged)saveBudgetData().catch(()=>{});
      } else {
        // New month - reset actuals to 0, income already loaded from config
        budgetData.groups.forEach(g=>g.subs.forEach(sub=>sub.actual=0));
        (budgetData.debts||[]).forEach((debt,di)=>{
          debt.abono=0;
          const did=debt.id;const op='debt_'+di;
          const prevSaldo=prevActuals?(prevActuals[did+'_saldo']!==undefined?prevActuals[did+'_saldo']:prevActuals[op+'_saldo']):undefined;
          if(prevSaldo!==undefined){
            debt.saldo=prevSaldo;
            debt.saldoInicialMes=prevSaldo;
          } else {
            debt.saldoInicialMes=debt.saldo||0;
          }
        });
      }
    }catch(e){budgetData={income:[],groups:getDefaultGroups(),debts:[]};}
  }

  // Load dashboard gastos for this month
  let dashboardTotals={};
  try{dashboardTotals=await loadMonthGastos();}catch(e){console.error('loadMonthGastos error:',e);}
  try{
    renderBudget(dashboardTotals);
  }catch(e){
    console.error('renderBudget crashed:',e);
    // Don't replace content on error - show what rendered so far
  }
}

async function ensureIds(){
  let changed=false;let t=Date.now();
  (budgetData.groups||[]).forEach(g=>{
    if(!g.id){g.id='grp_'+(t++);changed=true;}
    (g.subs||[]).forEach(sub=>{
      if(!sub.id){sub.id='sub_'+(t++);changed=true;}
    });
  });
  (budgetData.debts||[]).forEach(debt=>{
    if(!debt.id){debt.id='d_'+(t++);changed=true;}
  });
  if(changed){
    const config={
      groups:budgetData.groups.map(g=>({
        id:g.id,name:g.name,
        subs:g.subs.map(s=>({id:s.id,name:s.name,presup:s.presup,rubro:s.rubro}))
      })),
      debts:(budgetData.debts||[]).map(d=>({
        id:d.id,nombre:d.nombre,tipo:d.tipo,saldo:d.saldo,
        totalOriginal:d.totalOriginal,tasa:d.tasa,fechaPago:d.fechaPago
      }))
    };
    await userCol().doc('budget_config').set(config);
  }
}

