async function loadMonthGastos(){
  const totals={};
  cardPeriodSums={};
  const now=new Date();now.setHours(0,0,0,0);
  // Build per-card last cut dates
  const cardCutDates={};
  (budgetData.debts||[]).filter(d=>d.tipo==='tarjeta'&&d.fechaCorte).forEach(d=>{
    const thisMonthCut=new Date(now.getFullYear(),now.getMonth(),d.fechaCorte);
    cardCutDates[d.nombre]=thisMonthCut<=now?thisMonthCut:new Date(now.getFullYear(),now.getMonth()-1,d.fechaCorte);
  });
  const firstDay=new Date(budgetYear,budgetMonth,1);
  const lastDay=new Date(budgetYear,budgetMonth+1,0);
  const d=new Date(firstDay);
  const dow=d.getDay();
  d.setDate(d.getDate()-(dow===0?6:dow-1));
  const promises=[];
  while(d<=lastDay){
    const weekStart=new Date(d);
    const key='week_'+dk(weekStart);
    promises.push(userCol().doc(key).get().then(snap=>{
      if(!snap.exists)return;
      const data=snap.data();
      if(!data.gastos)return;
      Object.entries(data.gastos).forEach(([di,items])=>{
        if(!Array.isArray(items))return;
        const dayDate=new Date(weekStart);
        dayDate.setDate(weekStart.getDate()+parseInt(di));
        dayDate.setHours(0,0,0,0);
        items.forEach(g=>{
          if(!g.cat||!g.monto)return;
          totals[g.cat]=(totals[g.cat]||0)+g.monto;
          if(g.pagoCon&&cardCutDates[g.pagoCon]&&dayDate>=cardCutDates[g.pagoCon]){
            cardPeriodSums[g.pagoCon]=(cardPeriodSums[g.pagoCon]||0)+g.monto;
          }
        });
      });
    }).catch(()=>{}));
    d.setDate(d.getDate()+7);
  }
  await Promise.all(promises);
  return totals;
}

function saveBudgetConfig(){return saveBudgetData();}
async function saveBudgetData(){
  if(!db||!currentUser)return;
  // SAFETY: only skip if budgetData itself is null/undefined (truly corrupt)
  if(!budgetData||typeof budgetData!=='object'){
    console.warn('saveBudgetData: skipped — budgetData is null/undefined');
    return;
  }
  // Also skip if groups is undefined (not initialized yet)
  if(!Array.isArray(budgetData.groups)){
    console.warn('saveBudgetData: skipped — groups not initialized');
    return;
  }
  try{
    // Save backup BEFORE overwriting (so we can restore if something goes wrong)
    try{
      const prev=await userCol().doc('budget_config').get();
      if(prev.exists){
        await userCol().doc('budget_config_backup').set({
          ...prev.data(),
          _backup_ts: Date.now()
        });
      }
    }catch(e){console.warn('Backup failed (non-critical):',e);}

    // Save base config (presup + rubro + income)
    const config={
      income:budgetData.income||[],
      groups:budgetData.groups.map(g=>({
        id:g.id,name:g.name,
        subs:g.subs.map(sub=>({id:sub.id,name:sub.name,presup:sub.presup,rubro:sub.rubro}))
      })),
      debts:(budgetData.debts||[]).map(d=>({
        id:d.id,nombre:d.nombre,tipo:d.tipo,saldo:d.saldo,
        totalOriginal:d.totalOriginal,tasa:d.tasa,
        tasaTipo:d.tasaTipo||'',tasaAnual:d.tasaAnual||0,meses:d.meses||0,
        fechaPago:d.fechaPago,
        ...(d.saldoManualOverride?{saldoManualOverride:true}:{})
      }))
    };
    await userCol().doc('budget_config').set(config);
    // Save actuals for this month separately
    const monthKey='budget_actual_'+budgetYear+'_'+String(budgetMonth+1).padStart(2,'0');
    const actuals={};
    budgetData.groups.forEach((g)=>{
      g.subs.forEach((sub)=>{
        actuals[g.id+'_'+sub.id]=sub.actual||0;
      });
    });
    (budgetData.debts||[]).forEach((debt)=>{
      const did=debt.id;
      actuals[did+'_abono']=debt.abono||0;
      actuals[did+'_saldo']=debt.saldo||0;
      actuals[did+'_saldoInicial']=debt.saldoInicialMes!==undefined?debt.saldoInicialMes:debt.saldo||0;
    });
    await userCol().doc(monthKey).set(actuals);
  }catch(e){
    console.error('Budget save:',e);
    showToast(isEn()?'Could not save budget data. Check your connection.':'No se pudo guardar el presupuesto. Verifica tu conexión.');
  }
}

function corteDaysLeft(diaCorte){
  if(!diaCorte)return null;
  const now=new Date();now.setHours(0,0,0,0);
  const thisMonth=new Date(now.getFullYear(),now.getMonth(),diaCorte);
  const nextMonth=new Date(now.getFullYear(),now.getMonth()+1,diaCorte);
  const target=thisMonth>=now?thisMonth:nextMonth;
  return Math.round((target-now)/(1000*60*60*24));
}

function buildPagoSelect(){
  const sel=document.getElementById('gasto-pago');
  if(!sel)return;
  const es=!isEn();
  const prev=sel.value;
  sel.innerHTML=`<option value="Efectivo">${es?'Efectivo':'Cash'}</option><option value="Débito">${es?'Débito':'Debit'}</option><option value="Transferencia">${es?'Transferencia':'Transfer'}</option>`;
  (budgetData.debts||[]).filter(d=>d.tipo==='tarjeta').forEach(d=>{
    const opt=document.createElement('option');
    opt.value=d.nombre;opt.textContent='💳 '+d.nombre;
    sel.appendChild(opt);
  });
  if(prev&&Array.from(sel.options).some(o=>o.value===prev))sel.value=prev;
}

