async function budgetSaveDebt(di){
  const nombreEl=document.getElementById('d-nombre');
  const saldoEl=document.getElementById('d-saldo');
  if(!nombreEl||!saldoEl)return;
  const nombre=nombreEl.value.trim();
  const saldoVal=saldoEl.value.trim();
  let invalid=false;
  [nombreEl,saldoEl].forEach(el=>{el.style.borderColor='';el.style.background='';});
  if(!nombre){
    nombreEl.style.borderColor='#c0392b';
    nombreEl.style.background='rgba(192,57,43,0.06)';
    nombreEl.placeholder='Requerido';
    nombreEl.focus();
    invalid=true;
  }
  if(!saldoVal||parseFloat(saldoVal)===0){
    saldoEl.style.borderColor='#c0392b';
    saldoEl.style.background='rgba(192,57,43,0.06)';
    invalid=true;
  }
  if(invalid)return;
  const tipo=document.getElementById('d-tipo').value||'fijo';
  const saldo=parseFloat(document.getElementById('d-saldo').value)||0;
  const tasaTipo=(document.getElementById('d-tasa-tipo')||{}).value||'';
  const tasaAnual=parseFloat((document.getElementById('d-tasa-anual')||{}).value)||0;
  const meses=parseInt((document.getElementById('d-meses')||{}).value)||0;
  const debt={
    nombre,
    tipo,
    saldo,
    totalOriginal:parseFloat(document.getElementById('d-original').value)||saldo,
    tasa:parseFloat((document.getElementById('d-tasa')||{}).value)||0,
    tasaTipo,tasaAnual,meses,
    fechaPago:document.getElementById('d-fecha').value.trim(),
    fechaCorte:parseInt(document.getElementById('d-corte')?.value)||0,
    abono:0,
  };
  if(di===-1){
    debt.id='d_'+Date.now();
    debt.saldoInicialMes=saldo;
    budgetData.debts.push(debt);
  } else {
    const existing=budgetData.debts[di];
    debt.id=existing.id;
    debt.abono=existing.abono||0;
    debt.saldoInicialMes=existing.saldoInicialMes||saldo;
    budgetData.debts[di]=debt;
  }
  document.getElementById('debt-modal').remove();
  await saveBudgetConfig();
  const d=await loadMonthGastos();
  renderBudget(d);
}

async function budgetDelDebt(di){
  if(!confirm(!isEn()?'¿Eliminar esta deuda?':'Delete this debt?'))return;
  if(!budgetData.debts||!budgetData.debts[di])return;
  budgetData.debts.splice(di,1);
  await saveBudgetConfig();
  const d=await loadMonthGastos();
  renderBudget(d);
}

async function debtToggleSaldoOverride(di){
  if(!budgetData.debts||!budgetData.debts[di])return;
  const debt=budgetData.debts[di];
  if(debt.saldoManualOverride){
    delete debt.saldoManualOverride;
    await saveBudgetConfig();
    const d=await loadMonthGastos();
    renderBudget(d);
    return;
  }
  // Switch to manual — inline edit
  const es=!isEn();
  const balanceEl=document.querySelector(`#debt-card-balance-${di}`);
  const autoSum=cardPeriodSums[debt.nombre]||0;
  const input=document.createElement('input');
  input.type='number';input.value=autoSum;
  input.style.cssText='width:90px;font-size:14px;font-weight:600;color:var(--text);background:transparent;border:none;border-bottom:1.5px solid var(--mauve);outline:none;padding:0;';
  // Find the balance span and replace it
  const wrap=document.querySelector(`.debt-card:nth-child(${di+1}) .debt-card-balance span`);
  if(!wrap)return;
  const parent=wrap.parentNode;
  const iconSpan=parent.querySelector('span:last-child');
  wrap.replaceWith(input);
  if(iconSpan)iconSpan.style.display='none';
  input.focus();input.select();
  async function save(){
    try{
      const val=parseFloat(input.value)||0;
      debt.saldo=val;debt.saldoManualOverride=true;debt.saldoInicialMes=val;
      await saveBudgetConfig();
      const d=await loadMonthGastos();
      renderBudget(d);
    }catch(e){console.error('SaldoOverride save error:',e);showToast(isEn()?'Could not save':'No se pudo guardar');}
  }
  input.addEventListener('blur',save);
  input.addEventListener('keydown',async e=>{if(e.key==='Enter')input.blur();if(e.key==='Escape'){const d=await loadMonthGastos();renderBudget(d);}});
}

function debtEditAbono(di,cardEl){
  if(!budgetData.debts||!budgetData.debts[di])return;
  const debt=budgetData.debts[di];
  const es=!isEn();
  const isTarjeta=debt.tipo==='tarjeta';
  const valEl=document.getElementById('debt-abono-'+di);
  if(!valEl)return;
  const cur=isTarjeta?(debt.saldo||0):(debt.abono||0);
  const input=document.createElement('input');
  input.type='number';
  input.value=cur;
  input.style.cssText='width:80px;font-size:13px;font-weight:500;color:var(--teal);background:transparent;border:none;border-bottom:1.5px solid var(--teal);outline:none;padding:0;';
  valEl.replaceWith(input);
  input.focus();input.select();
  let _saving=false;
  async function save(){
    if(_saving)return;_saving=true;
    try{
      const val=parseFloat(input.value)||0;
      if(isTarjeta){
        if(debt.saldoInicialMes==null)debt.saldoInicialMes=debt.saldo??val;
        debt.saldo=val;
        debt.abono=Math.max(0,(debt.saldoInicialMes||0)-val);
      } else {
        if(debt.saldoInicialMes==null)debt.saldoInicialMes=debt.saldo??0;
        debt.abono=val;
        debt.saldo=Math.max(0,(debt.saldoInicialMes||0)-val);
      }
      await saveBudgetConfig();
      const d=await loadMonthGastos();
      renderBudget(d);
    }catch(e){console.error('Abono save error:',e);showToast(isEn()?'Could not save, try again':'No se pudo guardar, intenta de nuevo');}
    finally{_saving=false;}
  }
  input.addEventListener('blur',save);
  input.addEventListener('keydown',e=>{if(e.key==='Enter')input.blur();if(e.key==='Escape'){input.value=cur;input.blur();}});
}

